import{CursorPage}from"../../core/pagination.js";import{maybeMultipartFormRequestOptions}from"../../internal/uploads.js";import{APIResource}from"../../core/resource.js";import{path}from"../../internal/utils/path.js";import{Content}from"./content.js";import{Versions}from"./versions/versions.js";var Skills=class extends APIResource{constructor(){super(...arguments),this.content=new Content(this._client),this.versions=new Versions(this._client)}create(e={},n){return this._client.post(`/skills`,maybeMultipartFormRequestOptions({body:e,...n,__security:{bearerAuth:!0}},this._client))}retrieve(e,t){return this._client.get(path`/skills/${e}`,{...t,__security:{bearerAuth:!0}})}update(e,t,n){return this._client.post(path`/skills/${e}`,{body:t,...n,__security:{bearerAuth:!0}})}list(t={},n){return this._client.getAPIList(`/skills`,CursorPage,{query:t,...n,__security:{bearerAuth:!0}})}delete(e,t){return this._client.delete(path`/skills/${e}`,{...t,__security:{bearerAuth:!0}})}};Skills.Content=Content,Skills.Versions=Versions;export{Skills};